Javascript.validate:
var future = isFutureDate(Services.getValue(N79ADate.dataBinding));
var err = null;
if( future )
{	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
}
return err;

Context.isEnabled:
if(IsNewN79AsReqd.isEnabled())
{  	if( 'Y' != Services.getValue(IsNewN79AsReqd.dataBinding))
	{	return true;
	}
	return false;
}
return true;

Context.logic:
if( IsNewN79AsReqd.isEnabled() && 'Y' == Services.getValue(IsNewN79AsReqd.dataBinding))
{	Services.setValue(N79ADate.dataBinding, "");
}
else
{	Services.setValue( N79ADate.dataBinding , Services.getValue(N39HearingDate.dataBinding));
}
